/**
 * BFF Server - GraphQL Mesh + Static Assets
 * Generated by seans-mfe-tool
 * Following ADR-046: GraphQL Mesh with DSL-embedded configuration
 * Following ADR-063: TypeScript Mesh Configuration (Programmatic API)
 */
import express from 'express';
import path from 'path';
import cors from 'cors';
import helmet from 'helmet';
import { getMesh } from '@graphql-mesh/runtime';
import meshConfig from './mesh.config';
import type { Request, Response, NextFunction, Express } from 'express';
import crypto from 'crypto';

const app: Express = express();

// Security middleware
app.use(helmet({
  contentSecurityPolicy: {
    directives: {
      defaultSrc: ["'self'"],
      scriptSrc: ["'self'", "'unsafe-inline'", "'unsafe-eval'", "https://unpkg.com"],
      scriptSrcElem: ["'self'", "'unsafe-inline'", "https://unpkg.com"],
      styleSrc: ["'self'", "'unsafe-inline'", "https://unpkg.com"],
      styleSrcElem: ["'self'", "'unsafe-inline'", "https://unpkg.com"],
      imgSrc: ["'self'", 'data:', 'https:'],
      connectSrc: ["'self'", "https://unpkg.com"],
      workerSrc: ["'self'", 'blob:', "https://unpkg.com"],
      childSrc: ["'self'", 'blob:'],
      fontSrc: ["'self'", 'data:', "https://unpkg.com"],
    },
  },
}));

// CORS configuration
app.use(cors({
  origin: process.env.CORS_ORIGIN || '*',
  credentials: true,
}));

// Health check endpoint
app.get('/health', (req: express.Request, res: express.Response) => {
  res.json({ 
    status: 'healthy',
    name: 'new-dsl',
    version: '1.0.0',
    timestamp: new Date().toISOString()
  });
});

// GraphQL BFF endpoint with Programmatic API
// Following REQ-BFF-003: JWT Authentication Forwarding
// Following REQ-MESH-TS-004: Programmatic getMesh() API (v1.0)
interface MeshContext {
  jwt?: string;
  requestId: string;
  userId?: string;
}

// Initialize Mesh programmatically
let meshPromise: Promise<any> | null = null;

function getMeshInstance() {
  if (!meshPromise) {
    meshPromise = getMesh(meshConfig);
  }
  return meshPromise;
}

// JWT utility - extract user ID from token
function extractUserIdFromToken(authHeader?: string): string | undefined {
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return undefined;
  }
  
  try {
    const token = authHeader.replace('Bearer ', '');
    const payload = JSON.parse(Buffer.from(token.split('.')[1], 'base64').toString());
    return payload.sub || payload.userId || payload.id;
  } catch (error) {
    console.warn('Failed to extract user ID from token:', error);
    return undefined;
  }
}

// GraphQL endpoint with context injection (Mesh v1.0 API)
// Using GraphQL Yoga for HTTP handling with Mesh schema
import { createYoga } from 'graphql-yoga';

// Create Yoga instance with Mesh integration
const yoga = createYoga({
  schema: async () => {
    const mesh = await getMeshInstance();
    return mesh.schema;
  },
  context: async ({ request }) => {
    const authHeader = request.headers.get('authorization');
    return {
      jwt: authHeader?.replace('Bearer ', ''),
      requestId: request.headers.get('x-request-id') || crypto.randomUUID(),
      userId: extractUserIdFromToken(authHeader || undefined),
    } as MeshContext;
  },
  graphiql: process.env.NODE_ENV !== 'production',
  maskedErrors: process.env.NODE_ENV === 'production',
  logging: {
    debug: (...args) => console.log(...args),
    info: (...args) => console.log(...args),
    warn: (...args) => console.warn(...args),
    error: (...args) => console.error(...args),
  },
});

app.use('/graphql', yoga);


// Static MFE assets
// Following REQ-BFF-004: BFF + Static Assets Same Deployable
app.use(express.static(path.join(__dirname, 'dist')));

// SPA fallback - serve index.html for client-side routing
app.get('*', (req: express.Request, res: express.Response) => {
  res.sendFile(path.join(__dirname, 'dist', 'index.html'));
});


// Error handling
app.use((err: Error, req: express.Request, res: express.Response, next: express.NextFunction) => {
  console.error('Server error:', err);
  res.status(500).json({ 
    error: 'Internal Server Error',
    message: process.env.NODE_ENV === 'development' ? err.message : undefined
  });
});

const port = process.env.PORT || 4002;

// Initialize server with async Mesh setup
async function startServer() {
  try {
    // Pre-initialize Mesh to catch config errors early
    await getMeshInstance();
    console.log('✓ GraphQL Mesh initialized successfully');
    
    app.listen(port, () => {
      console.log(`🚀 new-dsl BFF server running on port ${port}`);
      console.log(`   GraphQL endpoint: http://localhost:${port}/graphql`);

      console.log(`   Static assets: http://localhost:${port}/`);

      console.log(`   Health check: http://localhost:${port}/health`);
      console.log(`   Config: mesh.config.ts (TypeScript, no build artifacts)`);
    });
  } catch (error) {
    console.error('Failed to start BFF server:', error);
    process.exit(1);
  }
}

startServer();

export default app;